// Import necessary libraries and components
import React, { useState } from 'react';
import { Grid, TextField, Button } from '@material-ui/core';
import { useDispatch } from 'react-redux';
import { setUserProfile } from '../actions/userActions';

// Define the UserProfilingForm component
function UserProfilingForm() {
  const [username, setUsername] = useState('');
  const [email, setEmail] = useState('');
  const dispatch = useDispatch();

  // Handle form submission
  const handleSubmit = (event: React.FormEvent<HTMLFormElement>) => {
    event.preventDefault();
    dispatch(setUserProfile({ username, email }));
  };

  return (
    <Grid container spacing={2} onSubmit={handleSubmit}>
      <Grid item xs={12}>
        <TextField
          label="Username"
          value={username}
          onChange={(event) => setUsername(event.target.value)}
          fullWidth
        />
      </Grid>
      <Grid item xs={12}>
        <TextField
          label="Email"
          value={email}
          onChange={(event) => setEmail(event.target.value)}
          fullWidth
        />
      </Grid>
      <Grid item xs={12}>
        <Button type="submit" variant="contained" color="primary">
          Save Profile
        </Button>
      </Grid>
    </Grid>
  );
}

// Export the UserProfilingForm component
export default UserProfilingForm;
```

