```filepath:server/graphql/schema.graphql
type User {
  id: ID!
  username: String!
  email: String!
  goals: [Goal]
  habits: [Habit]
  aiAdvices: [AIAdvice]
}

type Goal {
  id: ID!
  title: String!
  description: String!
  deadline: String!
  progress: Int!
}

type Habit {
  id: ID!
  name: String!
  frequency: String!
  streak: Int!
  progress: Int!
  reminders: [String]
}

type AIAdvice {
  id: ID!
  content: String!
  createdAt: String!
}

type AuthPayload {
  token: String!
  user: User!
}

type Query {
  user(id: ID!): User
  goals(userId: ID!): [Goal]
  habits(userId: ID!): [Habit]
  aiAdvices(userId: ID!): [AIAdvice]
}

type Mutation {
  registerUser(username: String!, email: String!, password: String!): AuthPayload
  createGoal(userId: ID!, title: String!, description: String!, deadline: String!): Goal
  createHabit(userId: ID!, name: String!, frequency: String!, reminders: [String]!): Habit
