```filepath:backend/src/resolvers.ts
import { ITask, Task } from './models/Task';
import { IUser, User } from './models/User';
import bcrypt from 'jsonwebtoken';
import jwt from 'jsonwebtoken';
import { IRequestWithUser } from './middleware/auth';

interface IAuthUser {
  id: string;
  email: string;
}

const resolvers = {
  Query: {
    tasks: async (_: any, __: any, context: any) => {
      const user = context.user as IAuthUser;
      return await Task.find({ userId: user.id });
    },
    aiSuggestions: () => {
      return [
        "Consider adding a task for daily exercise",
        "Don't forget to schedule weekly team meetings",
        "Set reminders for important deadlines"
      ];
    }
  },
  Mutation: {
    signup: async (_: any, { email, password }: { email: string, password: string }) => {
      const userExists = await User.findOne({ email });
      if (userExists) throw new Error('User already exists');

      const user = new User({
        email,
        password: await bcrypt.hash(password, 10)
      });

      await user.save();
      const token = jwt.sign({ id: user._id, email: user.email }, process.env.JWT_SECRET as string, {
        expiresIn: '7d'
      });

      return { token, user };
    },
    login: async (_: any, { email, password }: { email: string, password: string }) => {
      const user = await User.findOne({ email });
      if (!user) throw new Error('Invalid credentials');

      const isMatch = await bcrypt.compare(password, user.password);
      if (!isMatch) throw new Error('Invalid credentials');

      const token = jwt.sign({ id: user._id, email: user.email }, process.env.JWT_SECRET as string, {
        expiresIn: '7d'
      });

      return { token, user };
    },
    createTask: async (_: any, { title, description, dueDate }: { title: string, description: string, dueDate: Date }, context: any) => {
      const user = context.user as IAuthUser;
      const task = new Task({
        title,
        description,
        dueDate,
        userId: user.id
      });

      await task.save();
      return task;
    },
    updateTask: async (_: any, { id, completed }: { id: string, completed: boolean }, context: any) => {
      const user = context.user as IAuthUser;
      const task = await Task.findOneAndUpdate(
        { _id: id, userId: user.id },
        { completed },
        { new: true }
      );

      if (!task) throw new Error('Task not found');
      return task;
    },
    deleteTask: async (_: any, { id }: { id: string }, context: any) => {
      const user = context.user as IAuthUser;
      const task = await Task.findOneAndDelete({ _id: id, userId: user.id });

      if (!task) throw new Error('Task not found');
      return task;
    }
  }
};

export default resolvers;
```

